Do 'InicializaVariaveis'
MB 4 MT 2
Header print Cabecalho If &IsSintetico = true Print MenuSintetico Else Print MenuAnalitico EndIf End
if &isSintetico = true Do 'ImprimeDuplicatasSintetico' Do 'ImprimeClienteSinteticoTotalGeral' else Do 'ImprimeDuplicatasAnalitico' Do 'ImprimeClienteAnaliticoTotalGeral' endif
Do 'ImprimeLocalDeCobrancaMenu' Do 'ImprimePlanoDeContas'
Footer print Rodape End
// InicializaVariaveis Sub 'InicializaVariaveis' loadWWPContext.Call(&Context) If &Context.PesCod = 0 Return EndIf
RetornaConfSistema.Call(&Context.EmpCod, &Context.FilCod, domConfSistema.TCon077_ExibeStatusDebitoCliente, &TCon077_ExibeStatusDebitoCliente)
&PesRaz = &Context.PesRaz
For Each Order EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &FilFan = FilFan Exit EndFor
if not &CreFrpPgtoCod.IsEmpty() getConfigFormaPagamentoReceber.call(&EmpCod, &FilCod, &Context.PesCod, &CreFrpPgtoCod, &CreFrpPgtoTip, &FrpPgtoDest, &sdtFormaPagamentoContas, &sdtFormaPagamentoLocalCobranca, &sdtFormaPagamentoBandeira) Endif
If &isReceber = 'R' &titulo = 'DUPLICATAS PAGAS [CONTAS A RECEBER] ' Else &titulo = 'DUPLICATAS PAGAS [CONTAS A PAGAR] ' Endif
Do Case case &CreFrpPgtoTip = TipoDuplicata.CARTAOC &titulo += 'TIPO CARTÃO CRÉDITO' case &CreFrpPgtoTip = TipoDuplicata.CARTAOD &titulo += 'TIPO CARTÃO DÉBITO' case &CreFrpPgtoTip = TipoDuplicata.CHEQUEP &titulo += 'TIPO CHEQUE PRÓPRIO' case &CreFrpPgtoTip = TipoDuplicata.CHEQUET &titulo += 'TIPO CHEQUE TERCEIROS' case &CreFrpPgtoTip = TipoDuplicata.DINHEIRO &titulo += 'TIPO DINHEIRO' case &CreFrpPgtoTip = TipoDuplicata.DUPLICATA &titulo += 'TIPO DUPLICATA' case &CreFrpPgtoTip = TipoDuplicata.PIX &titulo += 'TIPO PIX' OtherWise &titulo += 'TODOS TIPOS' EndCase
&index = 0 &TotalGeralPago = 0 &TotalGeralDsc = 0 &TotalGeralJuros = 0 &CrePagTotItm = 0 &auxCreCliCod = 0 &AuxPlanCod = 0 &AuxPlanMoeda = 0 &CrePagTotItm = 0 &VetCreCbrCod() = 0 &VetCreCbrNom() = '' &VetCreVlrSdo() = 0 &VetCreVlrJur() = 0 &VetCreVlrDsc() = 0 &x = 1 EndSub
// ImprimeDuplicatasSintetico Sub 'ImprimeDuplicatasSintetico' For Each Order EmpCod,FilCod, CreCliRaz when &Ordem = 'C' Where EmpCod = &EmpCod Where FilCod = &FilCod Where CreRecPag = &isReceber Where CreFrpPgtoCod = &CreFrpPgtoCod when not &CreFrpPgtoCod.IsEmpty() Where CreFrpPgtoTip <> TipoDuplicata.CARTAOC and CreFrpPgtoTip <> TipoDuplicata.CARTAOD when &CreFrpPgtoCod.IsEmpty() Where CreCliCod = &CreCliCod when not &CreCliCod.IsEmpty() Where CrePagDta >= &CrePagDtaInicial when not &CrePagDtaInicial.IsEmpty() where CrePagDta <= &CrePagDtaFinal when not &CrePagDtaFinal.IsEmpty() Where CreVenCod = &PesCod When not &PesCod.IsEmpty() Where CreCliCobCidCod = &CidCod when not &CidCod.IsEmpty() Where CreCliCobUfeCod = &UfeCod when not &UfeCod.IsEmpty() Where CreVenAreCod = &AreCod when not &AreCod.IsEmpty() Where CreCbrCod = &CreCbrCod when not &CreCbrCod.IsEmpty() Where CreVlrSdo <> CreVlrDup //when &Status = 'P' Where not CrePedCod.IsEmpty() when &IsPedido = True Where CrePagSts <> Status_Caixa.Cancelado or CrePagSts.IsEmpty() or CrePagSts.IsNull() Where CreFilPgt = &CreFilPgt when not &CreFilPgt.IsEmpty()
if &index = 2 and (&Ordem = 'C' or &Ordem = 'D') If CreCliCod <> &auxCreCliCod Print ClienteSintetico NoSkip Print ClienteSinteticoItem &TotalPago = 0 &TotalJuros = 0 &TotalDesconto = 0 EndIf endif
If &AuxPlanCod <> CrePlanCod and not &AuxPlanCod.IsEmpty() do 'AddSDTPlanContas' Endif &AuxPlanCod = CrePlanCod &AuxPlanMoeda += CrePagTotItm
// print printBlock1
&index = 2 &AuxCreCliCod = CreCliCod &AuxCreCbrCod = CreCbrCod if &AuxCreCbrCod.IsEmpty() &AuxCreCbrCod = 1 EndiF
//############################ Atribuições da Tela #################################### &CrePagDta = CrePagDta &CreDupNro = CreDupNro &CreCliRaz = substr(CreCliCodRaz,1,30) &CreCliCobCidNom = substr(trim(CreCliCobCidNom),1,15)+'/'+CreCliCobUfeCod &CreVenCod = CreVenCod RetornaPrimeiroTelefone.Call(EmpCod,CreCliCod,&PesFonNum)
// VALORES POR LINHA &TotalPago += CrePagTotItm &TotalJuros += CrePagVlrJur &TotalDesconto += CrePagVlrDsc
// SOMA TOTAL AO FINAL DE TODOS OS RESULTADOS &TotalGeralPago += CrePagTotItm &TotalGeralJuros += CrePagVlrJur &TotalGeralDsc += CrePagVlrDsc
//#####################################################################################
//################## Contabiliza Total por Local de Cobrança ########################## &VetCreCbrCod(&AuxCreCbrCod) = &AuxCreCbrCod &VetCreCbrNom(&AuxCreCbrCod) = CreCbrNom &VetCreVlrSdo(&AuxCreCbrCod) += CrePagTotItm &VetCreVlrJur(&AuxCreCbrCod) += CrePagVlrJur &VetCreVlrDsc(&AuxCreCbrCod) += CrePagVlrDsc //##################################################################################### endfor
If &AuxPlanMoeda <> 0 do 'AddSDTPlanContas' Endif
if &index = 2 and (&Ordem = 'C' or &Ordem = 'D') Print ClienteSintetico NoSkip Print ClienteSinteticoItem &CrePagTotItm = 0 endif EndSub
//ImprimeTotalGeralAnalitico Sub 'ImprimeClienteSinteticoTotalGeral' print ClienteSinteticoTotalGeral EndSub
//ImprimeTotalGeral Sub 'ImprimeClienteAnaliticoTotalGeral' print ClienteAnaliticoTotalGeral EndSub
//ImprimeLocalDeCobrancaMenu Sub 'ImprimeLocalDeCobrancaMenu' print CobrancaMenu &Var = 1 Do while &Var <= rows(&VetCreCbrCod()) if &VetCreCbrCod(&Var) <> nullvalue(&VetCreCbrCod(&Var))
&LayCreCbrCod = &VetCreCbrCod(&Var) &LayCreCbrNom = &VetCreCbrNom(&Var) &LayCreVlrSdo = &VetCreVlrSdo(&Var) &LayCreVlrJur = &VetCreVlrJur(&Var) &LayCreVlrDsc = &VetCreVlrDsc(&Var) print CobrancaDetalhe endif &Var += 1 EndDo EndSub
//ImprimePlanoDeContas Sub 'ImprimePlanoDeContas' Print PlanoDeContasMenu &SdtTotalPlanoContas.Sort('PlanHiePadL') For &SdtTotalPlanoContasItem in &SdtTotalPlanoContas &PlanCodNOm = &SdtTotalPlanoContasItem.PlanCodNom &PlanMoeda = &SdtTotalPlanoContasItem.PlanMoeda print PlanoDeContasItem EndFor EndSub
// AddSDTPlanContas Sub 'AddSDTPlanContas' &IsAchou = false For &SdtTotalPlanoContasItem in &SdtTotalPlanoContas If &SdtTotalPlanoContasItem.planCod = &AuxPlanCod &SdtTotalPlanoContasItem.PlanMoeda += &AuxPlanMoeda &IsAchou = true exit EndIf EndFor
if &IsAchou = false For Each Order EmpCod, PlanCod Where EmpCod = &EmpCod Where PlanCod = &AuxPlanCod
&SdtTotalPlanoContasItem = new() &SdtTotalPlanoContasItem.PlanCod = PlanCod &SdtTotalPlanoContasItem.PlanCodNom = PlanCodNom &SdtTotalPlanoContasItem.PlanHie = PlanHie &SdtTotalPlanoContasItem.PlanHiePadL = PlanHiePadL &SdtTotalPlanoContasItem.PlanMoeda = &AuxPlanMoeda &SdtTotalPlanoContas.Add(&SdtTotalPlanoContasItem) // print printBlock4 Exit EndFor EndIf
&AuxPlanMoeda = 0
EndSub
// ImprimeDuplicatasAnalitico Sub 'ImprimeDuplicatasAnalitico'
For Each Order EmpCod,FilCod, CreCliRaz, (CrePagDta) when &Ordem = 'C' Order EmpCod,FilCod, CrePagDta, CreCliRaz when &Ordem = 'D' Where EmpCod = &EmpCod Where FilCod = &FilCod Where CreRecPag = &isReceber Where CreFrpPgtoCod = &CreFrpPgtoCod when not &CreFrpPgtoCod.IsEmpty() Where CreFrpPgtoTip <> TipoDuplicata.CARTAOC and CreFrpPgtoTip <> TipoDuplicata.CARTAOD when &CreFrpPgtoCod.IsEmpty() Where CreCliCod = &CreCliCod when not &CreCliCod.IsEmpty() Where CrePagDta >= &CrePagDtaInicial when not &CrePagDtaInicial.IsEmpty() where CrePagDta <= &CrePagDtaFinal when not &CrePagDtaFinal.IsEmpty() Where CreVenCod = &PesCod When not &PesCod.IsEmpty() Where CreCliCobCidCod = &CidCod when not &CidCod.IsEmpty() Where CreCliCobUfeCod = &UfeCod when not &UfeCod.IsEmpty() Where CreVenAreCod = &AreCod when not &AreCod.IsEmpty() Where CreCbrCod = &CreCbrCod when not &CreCbrCod.IsEmpty() Where CreVlrSdo <> CreVlrDup //when &Status = 'P' Where not CrePedCod.IsEmpty() when &IsPedido = True Where CrePagSts <> Status_Caixa.Cancelado or CrePagSts.IsEmpty() or CrePagSts.IsNull() Where CreFilPgt = &CreFilPgt when not &CreFilPgt.IsEmpty()
//######################### ADICIONA AO PLANO DE CONTAS ############################### If &AuxPlanCod <> CrePlanCod and not &AuxPlanCod.IsEmpty() do 'AddSDTPlanContas' Endif &AuxPlanCod = CrePlanCod &AuxPlanMoeda += CrePagTotItm //#####################################################################################
If &index = 2 and (&Ordem = 'D' or &Ordem = 'C') If CreCliCod <> &AuxCreCliCod Print ClienteAnaliticoTotal &x = 1 &TotalPago = 0 &TotalJuros = 0 &TotalDesconto = 0 EndIf EndIf
&index = 2 &AuxCreCliCod = CreCliCod &AuxCreVenCod = CreVenCod &AuxCreCbrCod = CreCbrCod If &AuxCreCbrCod.IsEmpty() &AuxCreCbrCod = 1 EndIf
//############################ Atribuições da Tela #################################### &CrePedCod = CrePedCod &CreCliRaz = substr(CreCliCodRaz,1,30) &CreCliCobCidNom = substr(trim(CreCliCobCidNom),1,15)+'/'+CreCliCobUfeCod &CrePagDta = CrePagDta RetornaPrimeiroTelefone.Call(EmpCod,CreCliCod,&PesFonNum)
// VALORES POR LINHA &CrePagTotItm = CrePagTotItm &CrePagVlrJur = CrePagVlrJur &CrePagVlrDsc = CrePagVlrDsc
// VALORES POR LINHA SOMA &TotalPago += CrePagTotItm &TotalJuros += CrePagVlrJur &TotalDesconto += CrePagVlrDsc
// SOMA TOTAL AO FINAL DE TODOS OS RESULTADOS &TotalGeralPago += CrePagTotItm &TotalGeralJuros += CrePagVlrJur &TotalGeralDsc += CrePagVlrDsc
//#####################################################################################
//################## Contabiliza Total por Local de Cobrança ########################## &VetCreCbrCod(&AuxCreCbrCod) = &AuxCreCbrCod &VetCreCbrNom(&AuxCreCbrCod) = CreCbrNom &VetCreVlrSdo(&AuxCreCbrCod) += CrePagTotItm &VetCreVlrJur(&AuxCreCbrCod) += CrePagVlrJur &VetCreVlrDsc(&AuxCreCbrCod) += CrePagVlrDsc //#####################################################################################
//################################ CASE IMPRESSÃO ############################################## Do Case Case (&x = 1 and (&Ordem = 'D' Or &Ordem = 'C')) Print ClienteAnalitico Noskip Print ClienteAnaliticoItem &x = 2 Case (&x = 2 and (&Ordem = 'D' Or &Ordem = 'C')) Print ClienteAnaliticoItem EndCase
//################################## IMPRESSÃO DAS OBSERVAÇÕES E COBRANÇAS ###################### If &IsMostrarObs = true
&Intobs = 1 For Each Order CreCobCod &CreMetNom = '' &CreResNom = '' If &Intobs = 1 Print Observacao &Intobs = 2 EndIf &CreMetNom = substr(CreMetNom,1,40) &CreResNom = substr(CreResNom,1,40) &CreCobObs = SubStr(CreCobObs,1,72) &CreCobObs2 = SubStr(CreCobObs,71,200) Print ObservacaoDesc If not &CreCobObs2.Trim().IsEmpty() Print ObservacaoDesc2 EndIf EndFor Endif
If &IsDetalhaPedido = true // Vai Mostrar o Pedido e os Produtos Daquele Pedido. if not CrePedCod.IsEmpty() &CrePedCod = CrePedCod
Do 'GetPedido' Else &CrePedCod = 0 EndIf EndIf
//################################################################################################ EndFor
If &AuxPlanMoeda <> 0 do 'AddSDTPlanContas' Endif
// ######################################### TOTAIS APOS SAIR DO FOR / SERVE PARA O UVarLTIMO REGISTRO Print ClienteAnaliticoTotal EndSub
Sub 'GetPedido' For Each Order EmpCod,FilCod,PedCod Where EmpCod = &EmpCod Where FilCod = &FilCod Where PedCod = &CrePedCod Print DetPedido
For each Order PedItmCod &ProCod = ProCod &ProNom = ProNom &PedQtd = PedQtd &PedVlrUnt = PedVlrUnt &PedVlritmComDsc = PedVlrItmComDsc Print DetPedidoProduto EndFor Print DetPedidoLine Exit EndFor EndSub
